// Rust-faithful Dafny port of RequestContext.rs::do_write_headers.
// Non-operational deviation: Rust's `FetchHeaders`/uWS response FFI objects are
// represented by small mutable Dafny classes so the header-removal control flow
// can be exercised directly.

datatype HTTPHeaderName =
  | ContentLength
  | TransferEncoding
  | Connection
  | KeepAlive
  | ProxyConnection
  | Upgrade

class Response {
  constructor ()
  {
  }
}

class FetchHeaders {
  var contentLength: bool
  var transferEncoding: bool
  var connection: bool
  var keepAlive: bool
  var proxyConnection: bool
  var upgrade: bool
  var wroteToUwsResponse: bool
  var lastRespKind: int

  constructor (
    contentLength_: bool,
    transferEncoding_: bool,
    connection_: bool,
    keepAlive_: bool,
    proxyConnection_: bool,
    upgrade_: bool
  )
  {
    contentLength := contentLength_;
    transferEncoding := transferEncoding_;
    connection := connection_;
    keepAlive := keepAlive_;
    proxyConnection := proxyConnection_;
    upgrade := upgrade_;
    wroteToUwsResponse := false;
    lastRespKind := 0;
  }

  method fast_remove(name: HTTPHeaderName)
    modifies this
    ensures contentLength == (if name == ContentLength then false else old(contentLength))
    ensures transferEncoding == (if name == TransferEncoding then false else old(transferEncoding))
    ensures connection == (if name == Connection then false else old(connection))
    ensures keepAlive == (if name == KeepAlive then false else old(keepAlive))
    ensures proxyConnection == (if name == ProxyConnection then false else old(proxyConnection))
    ensures upgrade == (if name == Upgrade then false else old(upgrade))
  {
    match name
    case ContentLength =>
      contentLength := false;
    case TransferEncoding =>
      transferEncoding := false;
    case Connection =>
      connection := false;
    case KeepAlive =>
      keepAlive := false;
    case ProxyConnection =>
      proxyConnection := false;
    case Upgrade =>
      upgrade := false;
  }

  method to_uws_response(resp_kind: int, resp: Response)
    modifies this
    ensures wroteToUwsResponse
    ensures lastRespKind == resp_kind
    ensures contentLength == old(contentLength)
    ensures transferEncoding == old(transferEncoding)
    ensures connection == old(connection)
    ensures keepAlive == old(keepAlive)
    ensures proxyConnection == old(proxyConnection)
    ensures upgrade == old(upgrade)
  {
    lastRespKind := resp_kind;
    wroteToUwsResponse := true;
  }
}

class RequestContext {
  var HTTP3: bool
  var resp: Response?
  var RESP_KIND: int

  constructor (http3: bool, resp_: Response?, resp_kind: int)
    ensures HTTP3 == http3
    ensures resp == resp_
    ensures RESP_KIND == resp_kind
  {
    HTTP3 := http3;
    resp := resp_;
    RESP_KIND := resp_kind;
  }

  method do_write_headers(headers: FetchHeaders)
    modifies headers
    ensures HTTP3 == old(HTTP3)
    ensures resp == old(resp)
    ensures RESP_KIND == old(RESP_KIND)
    ensures !headers.contentLength
    ensures !headers.transferEncoding
    ensures old(HTTP3) ==> !headers.connection
    ensures old(HTTP3) ==> !headers.keepAlive
    ensures old(HTTP3) ==> !headers.proxyConnection
    ensures old(HTTP3) ==> !headers.upgrade
    ensures old(resp) != null ==> headers.wroteToUwsResponse
    ensures old(resp) != null ==> headers.lastRespKind == old(RESP_KIND)
  {
    // ctx_log!("writeHeaders");
    headers.fast_remove(ContentLength);
    headers.fast_remove(TransferEncoding);
    if HTTP3 {
      // RFC 9114 §4.2: connection-specific fields are malformed.
      headers.fast_remove(Connection);
      headers.fast_remove(KeepAlive);
      headers.fast_remove(ProxyConnection);
      headers.fast_remove(Upgrade);
    }
    if resp != null {
      headers.to_uws_response(RESP_KIND, resp);
    }
  }
}

